<template><div><div class="page-title">设备管理</div><div class="page-card"><div class="toolbar"><el-input v-model="query.deviceName" placeholder="设备名称" clearable style="width:180px"/><el-input v-model="query.deviceNo" placeholder="设备编号" clearable style="width:180px"/><el-select v-model="query.status" placeholder="状态" clearable style="width:140px"><el-option label="正常" :value="1"/><el-option label="故障" :value="2"/><el-option label="维修中" :value="3"/><el-option label="停用" :value="4"/></el-select><el-button type="primary" @click="loadData">查询</el-button><el-button @click="reset">重置</el-button><el-button type="success" @click="openAdd">新增设备</el-button></div><el-table :data="records" v-loading="loading" border><el-table-column prop="id" label="ID" width="80"/><el-table-column prop="deviceNo" label="设备编号" width="160"/><el-table-column prop="deviceName" label="设备名称" min-width="180"/><el-table-column prop="deviceType" label="类型" width="120"/><el-table-column prop="areaCode" label="区域" width="100"/><el-table-column prop="location" label="位置" min-width="180"/><el-table-column label="状态" width="110"><template #default="{row}"><el-tag :type="deviceStatusTag(row.status)">{{ deviceStatusText(row.status) }}</el-tag></template></el-table-column><el-table-column label="操作" width="230" fixed="right"><template #default="{row}"><el-button size="small" @click="openEdit(row)">编辑</el-button><el-button size="small" type="warning" @click="openStatus(row)">状态</el-button><el-button size="small" type="danger" @click="remove(row)">删除</el-button></template></el-table-column></el-table><el-pagination style="margin-top:16px" background layout="total, prev, pager, next, sizes" :total="total" v-model:current-page="query.pageNo" v-model:page-size="query.pageSize" @current-change="loadData" @size-change="loadData"/></div><el-dialog v-model="dialogVisible" :title="form.id?'编辑设备':'新增设备'" width="560px"><el-form :model="form" label-width="90px"><el-form-item label="设备编号" v-if="!form.id"><el-input v-model="form.deviceNo"/></el-form-item><el-form-item label="设备名称"><el-input v-model="form.deviceName"/></el-form-item><el-form-item label="设备类型"><el-input v-model="form.deviceType"/></el-form-item><el-form-item label="区域"><el-input v-model="form.areaCode"/></el-form-item><el-form-item label="位置"><el-input v-model="form.location"/></el-form-item><el-form-item label="描述"><el-input v-model="form.description" type="textarea"/></el-form-item></el-form><template #footer><el-button @click="dialogVisible=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog><el-dialog v-model="statusVisible" title="修改设备状态" width="360px"><el-select v-model="statusForm.status" style="width:100%"><el-option label="正常" :value="1"/><el-option label="故障" :value="2"/><el-option label="维修中" :value="3"/><el-option label="停用" :value="4"/></el-select><template #footer><el-button @click="statusVisible=false">取消</el-button><el-button type="primary" @click="saveStatus">保存</el-button></template></el-dialog></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage,ElMessageBox } from 'element-plus';import { pageDevices,addDevice,updateDevice,deleteDevice,updateDeviceStatus } from '../api/device';const loading=ref(false),records=ref([]),total=ref(0);const query=reactive({pageNo:1,pageSize:10,deviceNo:'',deviceName:'',status:undefined});const dialogVisible=ref(false),statusVisible=ref(false);const form=reactive({});const statusForm=reactive({id:null,status:1});async function loadData(){loading.value=true;try{const data=await pageDevices(query);records.value=data?.records||[];total.value=data?.total||0}finally{loading.value=false}}function reset(){query.pageNo=1;query.deviceNo='';query.deviceName='';query.status=undefined;loadData()}function openAdd(){Object.assign(form,{id:null,deviceNo:'',deviceName:'',deviceType:'',areaCode:'',location:'',description:''});dialogVisible.value=true}function openEdit(row){Object.assign(form,row);dialogVisible.value=true}async function save(){form.id?await updateDevice(form):await addDevice(form);ElMessage.success('保存成功');dialogVisible.value=false;loadData()}function openStatus(row){statusForm.id=row.id;statusForm.status=Number(row.status);statusVisible.value=true}async function saveStatus(){await updateDeviceStatus(statusForm.id,{status:statusForm.status});ElMessage.success('状态已修改');statusVisible.value=false;loadData()}async function remove(row){await ElMessageBox.confirm(`确认删除设备 ${row.deviceName}？`,'提示',{type:'warning'});await deleteDevice(row.id);records.value=records.value.filter(i=>i.id!==row.id);total.value=Math.max(0,total.value-1);ElMessage.success('删除成功');await loadData()}function deviceStatusText(s){return {1:'正常',2:'故障',3:'维修中',4:'停用'}[Number(s)]||s}function deviceStatusTag(s){return {1:'success',2:'danger',3:'warning',4:'info'}[Number(s)]||'info'}onMounted(loadData)</script>
